### 4.4.3 PM Schedule Management Service

Handles manual PM modifications (drag-and-drop, manual reschedules) with full validation including Maximo status locks.

```typescript
/**
 * Service for manual PM schedule modifications.
 * 
 * CRITICAL: All modifications MUST validate against Maximo status to prevent
 * race conditions with in-progress work orders. The PMEditValidator from the
 * Integration layer (Part 7) provides this validation.
 * 
 * Operational reality (Maximo) MUST override planning data (MMS).
 */
class PMScheduleManagementService {
  private pmEditValidator: PMEditValidator;  // From Part 7
  private auditLogger: AuditLogger;

  /**
   * Move a PM to a new date (e.g., from canvas drag-and-drop).
   * 
   * @throws MaximoLockError if PM is in-progress in Maximo
   * @throws ComplianceWindowError if new date is outside allowed window
   * @throws TrackConflictError if track is occupied on new date
   */
  async movePM(
    pmId: string,
    newTargetDate: Date,
    newTrackId: string | null,
    userId: string
  ): Promise<PMScheduleRecord> {

    // 1. CRITICAL: Validate Maximo status lock
    const editValidation = await this.pmEditValidator.validateEdit(pmId);

    if (!editValidation.valid) {
      throw new PMEditBlockedError(
        editValidation.reason,
        editValidation.message,
        {
          maximoStatus: editValidation.maximoStatus,
          maximoWonum: editValidation.maximoWonum,
          suggestion: editValidation.suggestion
        }
      );
    }

    // 2. Load PM with all relationships
    const pm = await this.db.query.pmSchedule.findFirst({
      where: eq(pmSchedule.id, pmId),
      with: {
        pmType: true,
        train: true,
        assignedTrack: true
      }
    });

    if (!pm) {
      throw new NotFoundError('PM not found');
    }

    // 3. Validate compliance window
    if (newTargetDate < pm.constraintStart || newTargetDate > pm.constraintEnd) {
      throw new ComplianceWindowError(
        `Target date ${newTargetDate.toISOString().split('T')[0]} is outside compliance window`,
        {
          constraintStart: pm.constraintStart,
          constraintEnd: pm.constraintEnd,
          requestedDate: newTargetDate
        }
      );
    }

    // 4. Validate track availability (if track specified)
    if (newTrackId) {
      const conflict = await this.checkTrackConflict(
        newTrackId,
        newTargetDate,
        pm.pmType.minTrackDays,
        pmId  // Exclude self from conflict check
      );

      if (conflict) {
        throw new TrackConflictError(
          `Track ${conflict.trackNumber} is occupied by ${conflict.conflictingPMCode}`,
          conflict
        );
      }
    }

    // 5. Capture old state for audit
    const oldState = {
      targetDate: pm.targetDate,
      assignedTrackId: pm.assignedTrackId
    };

    // 6. Update PM schedule
    const updatedPM = await this.db.transaction(async (tx) => {
      // Update main record
      const [updated] = await tx.update(pmSchedule)
        .set({
          targetDate: newTargetDate,
          assignedTrackId: newTrackId ?? pm.assignedTrackId,
          updatedAt: new Date()
        })
        .where(eq(pmSchedule.id, pmId))
        .returning();

      // Record in history table
      await tx.insert(pmScheduleHistory).values({
        pmScheduleId: pmId,
        changeType: 'RESCHEDULE',
        fieldName: 'targetDate',
        oldValue: oldState.targetDate.toISOString(),
        newValue: newTargetDate.toISOString(),
        changedBy: userId,
        reason: 'Manual reschedule via canvas'
      });

      if (newTrackId && newTrackId !== pm.assignedTrackId) {
        await tx.insert(pmScheduleHistory).values({
          pmScheduleId: pmId,
          changeType: 'TRACK_REASSIGNMENT',
          fieldName: 'assignedTrackId',
          oldValue: oldState.assignedTrackId,
          newValue: newTrackId,
          changedBy: userId,
          reason: 'Track reassignment via canvas'
        });
      }

      return updated;
    });

    // 7. Update shadow record for Maximo sync
    await this.updateShadowRecord(pmId, {
      syncStatus: 'PENDING',
      pendingChanges: {
        targetDate: newTargetDate.toISOString(),
        trackId: newTrackId
      }
    });

    // 8. Audit log
    await this.auditLogger.log({
      action: 'PM_RESCHEDULED',
      entityType: 'PM_SCHEDULE',
      entityId: pmId,
      userId,
      changes: {
        targetDate: { old: oldState.targetDate, new: newTargetDate },
        assignedTrackId: { old: oldState.assignedTrackId, new: newTrackId }
      }
    });

    return updatedPM;
  }

  /**
   * Get PM with all relationships for canvas display.
   */
  async getPM(pmId: string): Promise<PMScheduleWithRelations> {
    const pm = await this.db.query.pmSchedule.findFirst({
      where: eq(pmSchedule.id, pmId),
      with: {
        pmType: true,
        train: true,
        assignedTrack: true,
        assignedDepot: true
      }
    });

    if (!pm) {
      throw new NotFoundError('PM not found');
    }

    return pm;
  }

  /**
   * Check if a track has conflicts for the given date range.
   */
  private async checkTrackConflict(
    trackId: string,
    startDate: Date,
    durationDays: number,
    excludePmId?: string
  ): Promise<TrackConflict | null> {
    const endDate = addDays(startDate, durationDays);

    const conflictingPM = await this.db.query.pmSchedule.findFirst({
      where: and(
        eq(pmSchedule.assignedTrackId, trackId),
        excludePmId ? ne(pmSchedule.id, excludePmId) : undefined,
        or(
          // New PM overlaps existing PM's start
          and(
            lte(pmSchedule.targetDate, startDate),
            gte(sql`${pmSchedule.targetDate} + ${durationDays} * interval '1 day'`, startDate)
          ),
          // New PM overlaps existing PM's end
          and(
            lte(pmSchedule.targetDate, endDate),
            gte(sql`${pmSchedule.targetDate} + ${durationDays} * interval '1 day'`, startDate)
          )
        ),
        inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS'])
      ),
      with: {
        pmType: true,
        train: true,
        assignedTrack: true
      }
    });

    if (conflictingPM) {
      return {
        trackId,
        trackNumber: conflictingPM.assignedTrack.trackNumber,
        conflictingPMId: conflictingPM.id,
        conflictingPMCode: conflictingPM.pmType.pmCode,
        conflictingTrainNumber: conflictingPM.train.trainNumber,
        conflictingDateRange: {
          start: conflictingPM.targetDate,
          end: addDays(conflictingPM.targetDate, conflictingPM.pmType.minTrackDays)
        }
      };
    }

    return null;
  }
}

/**
 * Custom error for PM edit blocks.
 */
class PMEditBlockedError extends Error {
  constructor(
    public reason: string,
    message: string,
    public details: {
      maximoStatus?: string;
      maximoWonum?: string;
      suggestion?: string;
    }
  ) {
    super(message);
    this.name = 'PMEditBlockedError';
  }
}

class ComplianceWindowError extends Error {
  constructor(
    message: string,
    public details: {
      constraintStart: Date;
      constraintEnd: Date;
      requestedDate: Date;
    }
  ) {
    super(message);
    this.name = 'ComplianceWindowError';
  }
}

class TrackConflictError extends Error {
  constructor(
    message: string,
    public conflict: TrackConflict
  ) {
    super(message);
    this.name = 'TrackConflictError';
  }
}

interface TrackConflict {
  trackId: string;
  trackNumber: string;
  conflictingPMId: string;
  conflictingPMCode: string;
  conflictingTrainNumber: string;
  conflictingDateRange: {
    start: Date;
    end: Date;
  };
}
